def is_balanced(s: str) -> bool:
    """
    Проверяет, сбалансированы ли скобки в строке.

    Функция обрабатывает три вида скобок: (), [], {}.
    Все остальные символы игнорируются.

    Args:
        s (str): Входная строка для проверки.

    Returns:
        bool: True, если все скобки сбалансированы, иначе False.
    """
    stack = []
    matching_bracket = {')': '(', ']': '[', '}': '{'}
    opening_brackets = set(matching_bracket.values())

    for char in s:
        if char in opening_brackets:
            stack.append(char)
        elif char in matching_bracket:
            if not stack or stack.pop() != matching_bracket[char]:
                return False

    return len(stack) == 0

